// CLX Verify Dashboard Access v1 — Parse + rate limit
// Rate limit: 60 requests per minute per source IP. In-memory cache
// within the n8n instance lifetime; replace with Redis for multi-
// worker deployments. IP extracted from Cloudflare headers if
// present (x-forwarded-for), else falls back to direct connection.

const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const headers = ($input.item.json && $input.item.json.headers) || {};

const token         = body.token || null;
const client_id     = body.client_id || null;
const requested_mode = String(body.requested_mode || 'client').toLowerCase();

const ip = headers['cf-connecting-ip']
  || (headers['x-forwarded-for'] || '').split(',')[0].trim()
  || headers['x-real-ip']
  || 'unknown';

// In-memory rate limiter (workflow scope). n8n restarts reset counts
// — acceptable for a single-instance deployment; switch to a shared
// Redis counter before horizontal scaling.
globalThis.__CLX_VERIFY_RL = globalThis.__CLX_VERIFY_RL || new Map();
const now = Date.now();
const windowMs = 60 * 1000;
const limit = 60;
const entry = globalThis.__CLX_VERIFY_RL.get(ip) || { count: 0, reset: now + windowMs };
if (now > entry.reset) {
  entry.count = 0;
  entry.reset = now + windowMs;
}
entry.count += 1;
globalThis.__CLX_VERIFY_RL.set(ip, entry);

if (entry.count > limit) {
  return { json: { _skip: true, _rate_limited: true, ip, authorized: false, role: 'guest', reason: 'rate_limit_exceeded' } };
}

if (!token) {
  return { json: { _skip: true, _invalid: true, ip, token: null, client_id, requested_mode, authorized: false, role: 'guest', reason: 'missing_token' } };
}

return { json: { token, client_id, requested_mode, ip, authorized: null, role: null, reason: null } };

// CLX Verify Dashboard Access v1 — Verify token + build response
// Resolution order:
//   1. MARY_MASTER_TOKEN match  -> role=admin (if requested) / ops (if requested_mode=ops)
//   2. clients.dashboard_token match AND client_id present -> role=client
//   3. else -> unauthorized

const parsed = $('Parse + Rate Limit').first().json;
const clientRows = $input.item.json;
const clientRow = Array.isArray(clientRows) ? clientRows[0] : clientRows;

const masterToken = process.env.MARY_MASTER_TOKEN || 'TODO_SET_MARY_MASTER_TOKEN';
const opsToken    = process.env.CLX_OPS_TOKEN     || null;

const token = parsed.token;
const client_id = parsed.client_id;
const requested_mode = parsed.requested_mode;

let authorized = false;
let role = 'guest';
let reason = null;

// Tier 1: master token
if (token && masterToken !== 'TODO_SET_MARY_MASTER_TOKEN' && token === masterToken) {
  authorized = true;
  if (requested_mode === 'ops') {
    role = 'ops';
  } else {
    role = 'admin';
  }
}
// Tier 2: ops-specific token (optional; admin token also works for ops)
else if (token && opsToken && token === opsToken) {
  authorized = true;
  role = 'ops';
}
// Tier 3: client token
else if (token && client_id && clientRow && clientRow.id && clientRow.dashboard_token
  && String(clientRow.dashboard_token) === String(token)) {
  authorized = true;
  role = 'client';
}
else {
  authorized = false;
  role = 'guest';
  reason = clientRow && clientRow.id ? 'token_mismatch' : (client_id ? 'client_not_found' : 'token_not_recognised');
}

return {
  json: {
    authorized,
    role,
    client_id: authorized && role === 'client' ? client_id : (role === 'admin' || role === 'ops' ? null : null),
    reason,
    ip: parsed.ip,
    requested_mode
  }
};
